 const anchors=document.querySelectorAll('a[href^="#"]');anchors.forEach(anchor=>{anchor.addEventListener('click',function(e){e.preventDefault();document.querySelector(this.getAttribute('href')).scrollIntoView({behavior:'smooth'});});});const items=document.querySelectorAll('.gallery-item');items.forEach(item=>{item.addEventListener('mouseenter',()=>{clearActive();item.classList.add('active');});item.addEventListener('mouseleave',()=>{item.classList.remove('active');});item.addEventListener('keydown',e=>{if(e.key==='Enter' || e.key===' '){e.preventDefault();clearActive();item.classList.toggle('active');}});item.addEventListener('touchstart',()=>{clearActive();item.classList.add('active');});});function clearActive(){items.forEach(i=> i.classList.remove('active'));}document.addEventListener('click',function(e){if(!e.target.closest('.gallery')){clearActive();}});
